  1	import { KeyboardEvent, MouseEvent as ReactMouseEvent, useCallback, useState, useMemo } from 'react';
  2	
  3	import { getValueFromNestedProperty } from '@core/utils/getValueFromNestedProperty';
  4	import { Card, CardBody, CardHeader, Flex, Text, TextContent, Title } from '@patternfly/react-core';
  5	import { SearchIcon } from '@patternfly/react-icons';
  6	import {
  7	  InnerScrollContainer,
  8	  SortByDirection,
  9	  Table,
 10	  TableText,
 11	  Tbody,
 12	  Td,
 13	  Th,
 14	  Thead,
 15	  ThProps,
 16	  Tr
 17	} from '@patternfly/react-table';
 18	
 19	import SkPagination from './SkPagination';
 20	import { NonNullableValue, SKTableProps } from '../../../interfaces/SkTable.interfaces';
 21	import EmptyData from '../EmptyData';
 22	
 23	const FIRST_PAGE_NUMBER = 1;
 24	const PAGINATION_PAGE_SIZE = 10;
 25	
 26	const SkTable = function <T>({
 27	  title,
 28	  columns,
 29	  rows = [],
 30	  customCells,
 31	  onGetFilters,
 32	  pagination = false,
 33	  alwaysShowPagination = true,
 34	  paginationPageSize = PAGINATION_PAGE_SIZE,
 35	  paginationTotalRows = rows.length,
 36	  ...props
 37	}: SKTableProps<T>) {
 38	  const [activeSortIndex, setActiveSortIndex] = useState<number>();
 39	  const [activeSortDirection, setActiveSortDirection] = useState<SortByDirection>();
 40	  const [currentPageNumber, setCurrentPageNumber] = useState<number>(FIRST_PAGE_NUMBER);
 41	  const [paginationSize, setPaginationSize] = useState<number>(paginationPageSize);
 42	
 43	  const skColumns = columns.filter(({ show }) => show !== false);
 44	
 45	  const getSortParams = useCallback(
 46	    (columnIndex: number): ThProps['sort'] => ({
 47	      sortBy: {
 48	        index: activeSortIndex,
 49	        direction: activeSortDirection
 50	      },
 51	      onSort: (_event: ReactMouseEvent, index: number, direction: SortByDirection) => {
 52	        if (onGetFilters) {
 53	          onGetFilters({
 54	            limit: paginationSize,
 55	            offset: (currentPageNumber - 1) * paginationSize,
 56	            sortName: index !== undefined && skColumns[index].prop,
 57	            sortDirection: direction
 58	          });
 59	        }
 60	
 61	        setActiveSortIndex(index);
 62	        setActiveSortDirection(direction);
 63	      },
 64	      columnIndex
 65	    }),
 66	    [activeSortDirection, activeSortIndex, skColumns, currentPageNumber, paginationSize, onGetFilters]
 67	  );
 68	
 69	  const handleSetPageNumber = useCallback(
 70	    (_: ReactMouseEvent | KeyboardEvent | MouseEvent, pageNumber: number) => {
 71	      setCurrentPageNumber(pageNumber);
 72	
 73	      if (onGetFilters) {
 74	        onGetFilters({
 75	          limit: paginationSize,
 76	          offset: (pageNumber - 1) * paginationSize,
 77	          sortName: activeSortIndex !== undefined && skColumns[activeSortIndex].prop,
 78	          sortDirection: activeSortDirection
 79	        });
 80	      }
 81	    },
 82	    [activeSortDirection, activeSortIndex, skColumns, onGetFilters, paginationSize]
 83	  );
 84	
 85	  const handleSetPaginationSize = useCallback(
 86	    (_: ReactMouseEvent | KeyboardEvent | MouseEvent, pageSizeSelected: number, newPage: number) => {
 87	      setPaginationSize(pageSizeSelected);
 88	      setCurrentPageNumber(FIRST_PAGE_NUMBER);
 89	
 90	      if (onGetFilters) {
 91	        onGetFilters({
 92	          limit: pageSizeSelected,
 93	          offset: (newPage - 1) * pageSizeSelected,
 94	          sortName: activeSortIndex !== undefined && skColumns[activeSortIndex].prop,
 95	          sortDirection: activeSortDirection
 96	        });
 97	      }
 98	    },
 99	    [activeSortDirection, activeSortIndex, skColumns, onGetFilters]
100	  );
101	
102	  let sortedRows = rows;
103	
104	  // enable the local sort and local pagination in case the onGetFilters is not defined
105	  if (!onGetFilters) {
106	    // Get the name of the currently active sort column, if any.
107	    const activeSortColumnName = skColumns[activeSortIndex || 0].prop;
108	
109	    if (activeSortColumnName) {
110	      // Sort the rows array based on the values of the currently active sort column and direction.
111	      const sortDirectionMultiplier = activeSortDirection === SortByDirection.desc ? -1 : 1;
112	      sortedRows = sortRowsByColumnName<T>(rows, activeSortColumnName as string, sortDirectionMultiplier);
113	    }
114	
115	    if (pagination) {
116	      sortedRows = sortedRows.slice(
117	        (currentPageNumber - 1) * paginationSize,
118	        (currentPageNumber - 1) * paginationSize + paginationSize
119	      );
120	    }
121	  }
122	
123	  const skRows = sortedRows.map((row, index) => ({
124	    id: index,
125	    columns: skColumns.map((column) => {
126	      const { prop } = column;
127	      const value = prop ? getValueFromNestedProperty(row, (prop as string).split('.') as (keyof T)[]) : '';
128	
129	      return {
130	        ...column,
131	        data: row,
132	        value
133	      };
134	    })
135	  }));
136	
137	  const isPaginationEnabled = useMemo(
138	    () => (pagination && paginationTotalRows > paginationPageSize) || alwaysShowPagination,
139	    [alwaysShowPagination, pagination, paginationPageSize, paginationTotalRows]
140	  );
141	
142	  const { shouldSort = false, isFullHeight = false, isPlain, ...restProps } = props;
143	
144	  return (
145	    <Card isFullHeight={isFullHeight} isPlain={isPlain || true}>
146	      {title && (
147	        <CardHeader>
148	          <TextContent>
149	            <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
150	              <Title headingLevel="h1">{title}</Title>
151	              {!isPaginationEnabled && (
152	                <Text>{`${paginationTotalRows || rows.length} ${rows.length === 1 ? 'item' : 'items'}`}</Text>
153	              )}
154	            </Flex>
155	          </TextContent>
156	        </CardHeader>
157	      )}
158	
159	      <CardBody style={{ padding: 0 }}>
160	        <InnerScrollContainer>
161	          <Table {...restProps} aria-label="sk-table">
162	            <Thead>
163	              <Tr>
164	                {skColumns.map(({ name, prop, columnDescription, isStickyColumn, modifier }, index) => (
165	                  <Th
166	                    aria-label={name || 'No value'}
167	                    colSpan={1}
168	                    key={name}
169	                    modifier={modifier}
170	                    isStickyColumn={isStickyColumn}
171	                    sort={(prop && shouldSort && getSortParams(index)) || undefined}
172	                    info={
173	                      columnDescription
174	                        ? {
175	                            tooltip: columnDescription,
176	                            tooltipProps: {
177	                              isContentLeftAligned: true
178	                            }
179	                          }
180	                        : undefined
181	                    }
182	                  >
183	                    {name}
184	                  </Th>
185	                ))}
186	              </Tr>
187	            </Thead>
188	
189	            <Tbody>
190	              {skRows.length === 0 && (
191	                <Tr>
192	                  <Td colSpan={12}>
193	                    <EmptyData icon={SearchIcon} />
194	                  </Td>
195	                </Tr>
196	              )}
197	
198	              {!(skRows.length === 0) &&
199	                skRows.map((row) => (
200	                  <Tr key={row.id}>
201	                    {row.columns.map(
202	                      ({ data, value, customCellName, callback, format, width, modifier, isStickyColumn }, index) => {
203	                        const Component = !!customCells && !!customCellName && customCells[customCellName];
204	
205	                        return (
206	                          <Td width={width} key={index} modifier={modifier} isStickyColumn={isStickyColumn}>
207	                            {Component && (
208	                              <Component
209	                                data={data}
210	                                value={value}
211	                                callback={callback}
212	                                format={format && format(value)}
213	                                fitContent={modifier === 'nowrap'}
214	                              />
215	                            )}
216	                            {!Component && (
217	                              <TableText wrapModifier={modifier === 'nowrap' ? 'fitContent' : 'truncate'}>
218	                                {(format && format(value)) || value}
219	                              </TableText>
220	                            )}
221	                          </Td>
222	                        );
223	                      }
224	                    )}
225	                  </Tr>
226	                ))}
227	            </Tbody>
228	          </Table>
229	        </InnerScrollContainer>
230	
231	        {isPaginationEnabled && (
232	          <SkPagination
233	            totalRow={paginationTotalRows}
234	            paginationSize={paginationSize}
235	            currentPageNumber={currentPageNumber}
236	            onSetPageNumber={handleSetPageNumber}
237	            onSetPaginationSize={handleSetPaginationSize}
238	          />
239	        )}
240	      </CardBody>
241	    </Card>
242	  );
243	};
244	
245	export default SkTable;
246	
247	function sortRowsByColumnName<T>(rows: NonNullableValue<T>[], columnName: string, direction: number) {
248	  return rows.sort((a, b) => {
249	    // Get the values of the sort column for the two rows being compared, and handle null values.
250	    const paramA = getValueFromNestedProperty(a, columnName.split('.') as (keyof T)[]);
251	    const paramB = getValueFromNestedProperty(b, columnName.split('.') as (keyof T)[]);
252	
253	    if (paramA == null || paramB == null || paramA === paramB) {
254	      return 0;
255	    }
256	
257	    return paramA > paramB ? direction : -direction;
258	  });
259	}

